    61→  constructor(baseURL: string, apiKey: string) {
    62→    // Strip trailing slash
    63→    this.baseURL = baseURL.replace(/\/+$/, "");
    64→    this.apiKey = apiKey;
    65→  }
    66→
    67→  private async request<T>(path: string, options: RequestInit = {}): Promise<T> {
    68→    const url = `${this.baseURL}${path}`;
    69→    const res = await fetch(url, {
    70→      ...options,
    71→      headers: {
    72→        "Content-Type": "application/json",
    73→        Authorization: `ApiKey ${this.apiKey}`,
    74→        ...options.headers,
    75→      },
    76→    });
    77→
    78→    if (!res.ok) {
    79→      const body = await res.text();
    80→      throw new Error(`TaskAI API error ${res.status}: ${body}`);
    81→    }
    82→
    83→    return res.json() as Promise<T>;
    84→  }
