   106→    if (params?.limit) qs.set("limit", String(params.limit));
   107→    const suffix = qs.toString() ? `?${qs}` : "";
   108→    return this.request(`/api/projects/${encodeURIComponent(projectId)}/tasks${suffix}`);
   109→  }
   110→
   111→  async getTaskByNumber(projectId: string, taskNumber: number): Promise<Task> {
